// GinServerOptions provides options for the Gin server.
type GinServerOptions struct {
	BaseURL      string
	Middlewares  []MiddlewareFunc
	ErrorHandler func(*gin.Context, error, int)
}

// RegisterHandlers creates http.Handler with routing matching OpenAPI spec.
func RegisterHandlers(router gin.IRouter, si ServerInterface) {
	RegisterHandlersWithOptions(router, si, GinServerOptions{})
}

// RegisterHandlersWithOptions creates http.Handler with additional options
func RegisterHandlersWithOptions(router gin.IRouter, si ServerInterface, options GinServerOptions) {
	errorHandler := options.ErrorHandler
	if errorHandler == nil {
		errorHandler = func(c *gin.Context, err error, statusCode int) {
			c.JSON(statusCode, gin.H{"msg": err.Error()})
		}
	}

	wrapper := ServerInterfaceWrapper{
		Handler:            si,
		HandlerMiddlewares: options.Middlewares,
		ErrorHandler:       errorHandler,
	}

	router.GET(options.BaseURL+"/healthz", wrapper.Healthz)
	router.GET(options.BaseURL+"/readyz", wrapper.Readyz)
	router.POST(options.BaseURL+"/v1/auth/login", wrapper.Login)
	router.POST(options.BaseURL+"/v1/auth/logout", wrapper.Logout)
	router.POST(options.BaseURL+"/v1/auth/refresh", wrapper.RefreshToken)
	router.POST(options.BaseURL+"/v1/auth/register", wrapper.Register)
	router.GET(options.BaseURL+"/v1/projects", wrapper.ListProjects)
	router.POST(options.BaseURL+"/v1/projects", wrapper.CreateProject)
	router.DELETE(options.BaseURL+"/v1/projects/:id", wrapper.DeleteProject)
	router.GET(options.BaseURL+"/v1/projects/:id", wrapper.GetProject)
	router.PATCH(options.BaseURL+"/v1/projects/:id", wrapper.UpdateProject)
	router.GET(options.BaseURL+"/v1/projects/:id/stats", wrapper.GetProjectStats)
	router.GET(options.BaseURL+"/v1/projects/:id/tasks", wrapper.ListTasks)
	router.POST(options.BaseURL+"/v1/projects/:id/tasks", wrapper.CreateTask)
	router.DELETE(options.BaseURL+"/v1/tasks/:id", wrapper.DeleteTask)
	router.GET(options.BaseURL+"/v1/tasks/:id", wrapper.GetTask)
	router.PATCH(options.BaseURL+"/v1/tasks/:id", wrapper.UpdateTask)
	router.GET(options.BaseURL+"/v1/tasks/:id/comments", wrapper.ListComments)
	router.POST(options.BaseURL+"/v1/tasks/:id/comments", wrapper.CreateComment)
	router.POST(options.BaseURL+"/v1/tasks/:id/transitions", wrapper.TransitionTask)
	router.GET(options.BaseURL+"/v1/users/me", wrapper.GetMe)
	router.PATCH(options.BaseURL+"/v1/users/me", wrapper.UpdateMe)
}
